import piece.*;
import plateau.Grille;

import java.util.Collection;

public class Game {
    private Collection[][] Grille;

    public void isGagne(){

    }
    public void startGame(){
        Grille grille = new Grille();
        grille.initEchequier();

        // Pièces Blanches - Rangée 0
        Tour tourBlanc1 = new Tour(0, 0, Couleur.BLANC);
        Tour tourBlanc2 = new Tour(0, 7, Couleur.BLANC);
        Cavalier cavalierBlanc1 = new Cavalier(0, 1, Couleur.BLANC);
        Cavalier cavalierBlanc2 = new Cavalier(0, 6, Couleur.BLANC);
        Fou fouBlanc1 = new Fou(0, 2, Couleur.BLANC);
        Fou fouBlanc2 = new Fou(0, 5, Couleur.BLANC);
        Roi roiBlanc = new Roi(0, 4, Couleur.BLANC);
        Reine reineBlanche = new Reine(0, 3, Couleur.BLANC);

        // Pions Blancs - Rangée 1
        Pion pionBlanc1 = new Pion(1, 0, Couleur.BLANC);
        Pion pionBlanc2 = new Pion(1, 1, Couleur.BLANC);
        Pion pionBlanc3 = new Pion(1, 2, Couleur.BLANC);
        Pion pionBlanc4 = new Pion(1, 3, Couleur.BLANC);
        Pion pionBlanc5 = new Pion(1, 4, Couleur.BLANC);
        Pion pionBlanc6 = new Pion(1, 5, Couleur.BLANC);
        Pion pionBlanc7 = new Pion(1, 6, Couleur.BLANC);
        Pion pionBlanc8 = new Pion(1, 7, Couleur.BLANC);

        // Pions Noirs - Rangée 6
        Pion pionNoir1 = new Pion(6, 0, Couleur.NOIR);
        Pion pionNoir2 = new Pion(6, 1, Couleur.NOIR);
        Pion pionNoir3 = new Pion(6, 2, Couleur.NOIR);
        Pion pionNoir4 = new Pion(6, 3, Couleur.NOIR);
        Pion pionNoir5 = new Pion(6, 4, Couleur.NOIR);
        Pion pionNoir6 = new Pion(6, 5, Couleur.NOIR);
        Pion pionNoir7 = new Pion(6, 6, Couleur.NOIR);
        Pion pionNoir8 = new Pion(6, 7, Couleur.NOIR);

        // Pièces Noires - Rangée 7
        Tour tourNoir1 = new Tour(7, 0, Couleur.NOIR);
        Tour tourNoir2 = new Tour(7, 7, Couleur.NOIR);
        Cavalier cavalierNoir1 = new Cavalier(7, 1, Couleur.NOIR);
        Cavalier cavalierNoir2 = new Cavalier(7, 6, Couleur.NOIR);
        Fou fouNoir1 = new Fou(7, 2, Couleur.NOIR);
        Fou fouNoir2 = new Fou(7, 5, Couleur.NOIR);
        Roi roiNoir = new Roi(7, 4, Couleur.NOIR);
        Reine reineNoire = new Reine(7, 3, Couleur.NOIR);
    }

}
